// Format alert for any BLOCK or ESCALATE actions
const pipeline = $('Pipeline: GovernLayer API').item.json;
const scan = $('Quick Scan: Achonye').item.json;
const health = $('Health Check').item.json;

const alerts = [];

if (pipeline.governance_action !== 'APPROVE') {
  alerts.push({
    system: pipeline.system,
    action: pipeline.governance_action,
    reason: pipeline.reason,
    risk_score: pipeline.risk_score,
    drift: pipeline.drift_coefficient
  });
}

if (scan.action !== 'APPROVE') {
  alerts.push({
    system: scan.system,
    action: scan.action,
    risk_score: scan.risk_score,
    drift: scan.drift_coefficient
  });
}

const degradedServices = Object.entries(health.services || {})
  .filter(([_, v]) => v.status !== 'up')
  .map(([k, _]) => k);

return [{
  json: {
    timestamp: new Date().toISOString(),
    alerts_count: alerts.length,
    alerts,
    degraded_services: degradedServices,
    overall_health: health.overall,
    summary: alerts.length > 0
      ? `ACTION REQUIRED: ${alerts.map(a => `${a.system} -> ${a.action}`).join(', ')}`
      : 'All systems nominal'
  }
}];

// Log successful run
const pipeline = $('Pipeline: GovernLayer API').item.json;
const scan = $('Quick Scan: Achonye').item.json;

return [{
  json: {
    timestamp: new Date().toISOString(),
    status: 'all_clear',
    systems_checked: 2,
    results: [
      { system: pipeline.system, action: pipeline.governance_action, risk: pipeline.risk_score },
      { system: scan.system, action: scan.action, risk: scan.risk_score }
    ]
  }
}];
